const searches = [
  { keyword: 'customer-success-manager', location: 'delhi-ncr', label: 'CSM Delhi' },
  { keyword: 'project-coordinator', location: 'delhi-ncr', label: 'PC Delhi' },
  { keyword: 'client-operations', location: 'noida', label: 'ClientOps Noida' },
  { keyword: 'operations-manager', location: 'delhi-ncr', label: 'Ops Delhi' },
  { keyword: 'business-development-manager', location: 'delhi-ncr', label: 'BDM Delhi' },
  { keyword: 'account-manager', location: 'delhi-ncr', label: 'AM Delhi' },
  { keyword: 'business-analyst', location: 'delhi-ncr', label: 'BA Delhi' }
];

return searches.map(s => ({
  json: {
    url: `https://www.naukri.com/jobapi/v3/search?noOfResults=20&urlType=search_by_keyword&searchType=adv&keyword=${s.keyword}&location=${s.location}&pageNo=1&experience=2&exprangeFrom=2&exprangeTo=6&jobAge=1&sort=1`,
    label: s.label,
    source_platform: 'naukri'
  }
}));

const response = $input.first().json;
const sourcePlatform = $('Build Search URLs').first().json.source_platform;

const jobs = [];
const listings = (response.jobDetails || response.jobs || []);

for (const job of listings) {
  jobs.push({
    job_id: job.jobId || job.id || '',
    job_title: job.title || job.jobTitle || '',
    company: job.companyName || job.company || '',
    location: (job.placeholders && job.placeholders[1] && job.placeholders[1].label) || job.location || '',
    job_url: job.jdURL || `https://www.naukri.com/job-listings-${job.jobId}`,
    description: job.jobDescription || job.description || '',
    source_platform: sourcePlatform
  });
}

return jobs.map(j => ({ json: j }));

const seen = $getWorkflowStaticData('global');
if (!seen.naukriSeenUrls) seen.naukriSeenUrls = [];

const item = $input.first().json;
if (seen.naukriSeenUrls.includes(item.job_url)) return [];

seen.naukriSeenUrls.push(item.job_url);
if (seen.naukriSeenUrls.length > 2000) seen.naukriSeenUrls = seen.naukriSeenUrls.slice(-1000);

return [{ json: item }];
